openscad:
case_diameter = 40; // [20:1:80]
case_height = 8; // [4:0.5:15]
dial_thickness = 1.5; // [0.5:0.5:4]
hand_width = 1.2; // [0.8:0.2:3]
minute_hand_length = 15; // [8:1:25]
hour_hand_length = 10; // [5:1:18]
second_hand_length = 16; // [8:1:22]
lug_width = 20; // [12:1:30]
$fn = 60;
module watch() {
    color("silver")
    difference() {
        union() {
            cylinder(d=case_diameter, h=case_height);
            translate([-case_diameter/2-4, -lug_width/2, case_height/2-2])
                cube([8, lug_width, 4]);
            translate([case_diameter/2-4, -lug_width/2, case_height/2-2])
                cube([8, lug_width, 4]);
        }
        translate([0,0,case_height-1.5])
            cylinder(d=case_diameter-4, h=3);
    }
    color([0.039,0.729,0.71])
    translate([0,0,case_height-1.5])
        cylinder(d=case_diameter-5, h=dial_thickness);
    color("red") {
        translate([0,0,case_height-0.3])
            cylinder(d=hand_width, h=1.5);
        translate([0,0,case_height-0.2])
            rotate([0,0,30])
                cube([hand_width, minute_hand_length, 1.2], center=true);
        translate([0,0,case_height-0.1])
            rotate([0,0,120])
                cube([hand_width, hour_hand_length, 1.2], center=true);
        translate([0,0,case_height])
            rotate([0,0,200])
                cube([hand_width*0.6, second_hand_length, 0.8], center=true);
    }
}
watch();
